#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;


// red channel - the soft background with a spreading factor

    vec2 d = uTexSize.zw * 8; // the distance in pixels where the gradient is calculated from
    vec3 dx = ( GetBlur1(vUv + vec2(1,0)*d) - GetBlur1(vUv-vec2(1,0)*d) );
    vec3 dy = ( GetBlur1(vUv + vec2(0,1)*d) - GetBlur1(vUv-vec2(0,1)*d) );
    // working with gradients in the pic as motion vectors

    vec2 dither_uv = vUvOriginal*uTexSize.xy*texsize_noise_lq.zw * 1.2 // makes the graininess of the fur
                                                                    // 0.5 (very raw) - 3 (fine leather)
                       + rand_frame.xy;    // needs to be set to keep an overall randomness

    vec2 uv_bg = mix(vUvOriginal,vUv,0.4)   // scaling the input motion vector down, useful for a lower layer
                   + vec2(dx.x,dy.x)*uTexSize.zw  *2; // important: this is the spreading factor.
                                                       // 1 to 8 are good values
                                                       // (dependent on the distance the gradient is taken from)

    ret.x = GetPixel(uv_bg).x
            - (GetPixel(uv_bg).x - GetBlur3(uv_bg).x)  * 0.02  // this part darkens the most contrasty parts only
                                                               // try differnet blur levels too
            - 0.004  // overall fade to black
                     // the play of the upper two factors makes the 3D impact
            +(texture(sampler_noise_lq, dither_uv).xyz-0.5) *0.12;  // intensity of the hairs (0.04 - 0.4)


// green: nice fading clouds - diffusion dissolution

vec2 uv_mid = mix(vUvOriginal,vUv,0.3) +(texture(sampler_noise_lq, dither_uv).xyz-0.5)*uTexSize.zw*3;
 ret.y = GetPixel(uv_mid).y - 0.004;


// blue channel

vec2 uv_fg = vUv;
   ret.z = GetPixel(uv_fg).z;
   ret.z += (ret.z - GetBlur1(uv_fg).z)*0.1 - 0.015; // assuring there will not be any solid areas - breaking up effect


  fragColor = ret;
}

